import { z } from "zod";

export const ComponentTypeSchema = z.enum([
  "voltage_source",
  "resistor",
  "wire",
  "switch",
  "ammeter",
  "voltmeter",
  "bulb",
]);

export const ComponentSchema = z.object({
  id: z.string().min(1),
  type: ComponentTypeSchema,
  value: z.number().optional(),
  unit: z.string().optional(),
  nodes: z.tuple([z.string(), z.string()]),
  closed: z.boolean().optional(),
});

export const LayoutPointSchema = z.object({
  x: z.number(),
  y: z.number(),
});

export const CircuitSchema = z.object({
  name: z.string().default("Untitled circuit"),
  components: z.array(ComponentSchema).min(1),
  layout: z.record(LayoutPointSchema).optional(),
  warnings: z.array(z.string()).optional(),
});

export type ComponentType = z.infer<typeof ComponentTypeSchema>;
export type Component = z.infer<typeof ComponentSchema>;
export type LayoutPoint = z.infer<typeof LayoutPointSchema>;
export type Circuit = z.infer<typeof CircuitSchema>;

export function validateCircuit(data: unknown): {
  success: true;
  circuit: Circuit;
} | {
  success: false;
  errors: string[];
} {
  const result = CircuitSchema.safeParse(data);
  if (!result.success) {
    return {
      success: false,
      errors: result.error.errors.map((e) => `${e.path.join(".")}: ${e.message}`),
    };
  }

  const circuit = result.data;
  const errors: string[] = [];
  const ids = new Set<string>();

  for (const comp of circuit.components) {
    if (ids.has(comp.id)) {
      errors.push(`Duplicate component id: ${comp.id}`);
    }
    ids.add(comp.id);

    if (comp.type === "voltage_source" && comp.value === undefined) {
      errors.push(`${comp.id}: voltage_source requires value`);
    }
    if (
      (comp.type === "resistor" || comp.type === "bulb") &&
      comp.value === undefined
    ) {
      errors.push(`${comp.id}: ${comp.type} requires value (resistance in ohms)`);
    }
    if (comp.type === "switch" && comp.closed === undefined) {
      comp.closed = true;
    }
  }

  if (errors.length > 0) {
    return { success: false, errors };
  }

  return { success: true, circuit };
}

