import type { Circuit, Component } from "./schema.js";

export interface BranchResult {
  componentId: string;
  current: number;
  voltageDrop: number;
  power: number;
  fromNode: string;
  toNode: string;
}

export interface SolveResult {
  success: true;
  nodeVoltages: Record<string, number>;
  branches: BranchResult[];
  totalCurrent: number;
  equivalentResistance: number | null;
  explanations: string[];
}

export interface SolveError {
  success: false;
  error: string;
}

function getConductance(comp: Component): number | null {
  switch (comp.type) {
    case "resistor":
    case "bulb":
      if (!comp.value || comp.value <= 0) return null;
      return 1 / comp.value;
    case "ammeter":
      return 1 / 0.001;
    case "voltmeter":
      return 1e-9;
    case "wire":
      return 1e6;
    case "switch":
      return comp.closed !== false ? 1e6 : 0;
    case "voltage_source":
      return null;
    default:
      return null;
  }
}

function getSourceVoltage(comp: Component): number | null {
  if (comp.type === "voltage_source") {
    return comp.value ?? 0;
  }
  return null;
}

function gaussianElimination(A: number[][], b: number[]): number[] | null {
  const n = b.length;
  const M = A.map((row, i) => [...row, b[i]]);

  for (let col = 0; col < n; col++) {
    let pivot = col;
    for (let row = col + 1; row < n; row++) {
      if (Math.abs(M[row][col]) > Math.abs(M[pivot][col])) pivot = row;
    }
    if (Math.abs(M[pivot][col]) < 1e-12) return null;
    [M[col], M[pivot]] = [M[pivot], M[col]];

    for (let row = col + 1; row < n; row++) {
      const factor = M[row][col] / M[col][col];
      for (let j = col; j <= n; j++) {
        M[row][j] -= factor * M[col][j];
      }
    }
  }

  const x = new Array(n).fill(0);
  for (let row = n - 1; row >= 0; row--) {
    let sum = M[row][n];
    for (let col = row + 1; col < n; col++) {
      sum -= M[row][col] * x[col];
    }
    if (Math.abs(M[row][row]) < 1e-12) return null;
    x[row] = sum / M[row][row];
  }
  return x;
}

export function solveCircuit(circuit: Circuit): SolveResult | SolveError {
  const nodes = new Set<string>();
  for (const comp of circuit.components) {
    nodes.add(comp.nodes[0]);
    nodes.add(comp.nodes[1]);
  }

  const nodeList = Array.from(nodes);
  const ground = nodeList.includes("gnd")
    ? "gnd"
    : nodeList.includes("n0")
      ? "n0"
      : nodeList[0];

  const unknownNodes = nodeList.filter((n) => n !== ground);
  if (unknownNodes.length === 0) {
    return { success: false, error: "Circuit has no nodes to analyze." };
  }

  const n = unknownNodes.length;
  const G: number[][] = Array.from({ length: n }, () => new Array(n).fill(0));
  const I: number[] = new Array(n).fill(0);

  for (const comp of circuit.components) {
    const [a, b] = comp.nodes;
    const srcV = getSourceVoltage(comp);

    if (srcV !== null) {
      const posNode = a;
      const negNode = b;
      const Rint = 0.01;
      const g = 1 / Rint;

      const stamp = (node: string, sign: number) => {
        if (node === ground) return;
        const idx = unknownNodes.indexOf(node);
        if (idx >= 0) {
          G[idx][idx] += g;
          I[idx] += sign * g * srcV;
        }
      };

      stamp(posNode, 1);
      stamp(negNode, -1);

      if (posNode !== ground && negNode !== ground) {
        const i = unknownNodes.indexOf(posNode);
        const j = unknownNodes.indexOf(negNode);
        G[i][j] -= g;
        G[j][i] -= g;
      } else if (posNode !== ground) {
        const i = unknownNodes.indexOf(posNode);
        const j = unknownNodes.indexOf(negNode);
        if (j >= 0) G[i][j] -= g;
      } else if (negNode !== ground) {
        const i = unknownNodes.indexOf(negNode);
        const j = unknownNodes.indexOf(posNode);
        if (j >= 0) G[i][j] -= g;
      }
      continue;
    }

    const g = getConductance(comp);
    if (g === null) continue;
    if (g === 0) continue;

    const stampResistor = (n1: string, n2: string) => {
      if (n1 !== ground) {
        const i = unknownNodes.indexOf(n1);
        G[i][i] += g;
      }
      if (n2 !== ground) {
        const j = unknownNodes.indexOf(n2);
        G[j][j] += g;
      }
      if (n1 !== ground && n2 !== ground) {
        const i = unknownNodes.indexOf(n1);
        const j = unknownNodes.indexOf(n2);
        G[i][j] -= g;
        G[j][i] -= g;
      }
    };

    stampResistor(a, b);
  }

  const voltages = gaussianElimination(G, I);
  if (!voltages) {
    return {
      success: false,
      error: "Cannot solve circuit (open circuit, short circuit, or singular matrix).",
    };
  }

  const nodeVoltages: Record<string, number> = { [ground]: 0 };
  unknownNodes.forEach((node, idx) => {
    nodeVoltages[node] = voltages[idx];
  });

  const branches: BranchResult[] = [];
  let sourceCurrent = 0;

  for (const comp of circuit.components) {
    const [a, b] = comp.nodes;
    const va = nodeVoltages[a] ?? 0;
    const vb = nodeVoltages[b] ?? 0;
    const vDrop = va - vb;

    let current = 0;
    const srcV = getSourceVoltage(comp);

    if (srcV !== null) {
      const Rint = 0.01;
      current = (vDrop - srcV) / Rint;
      sourceCurrent = Math.abs(current);
    } else {
      const g = getConductance(comp);
      if (g !== null && g > 0 && g < 1e5) {
        current = vDrop * g;
      } else if (g !== null && g >= 1e5) {
        current = vDrop * 1e6;
      }
    }

    const power = Math.abs(current * vDrop);

    branches.push({
      componentId: comp.id,
      current,
      voltageDrop: vDrop,
      power,
      fromNode: a,
      toNode: b,
    });
  }

  const explanations = buildExplanations(circuit, branches, nodeVoltages, sourceCurrent);

  const resistors = circuit.components.filter(
    (c) => c.type === "resistor" || c.type === "bulb"
  );
  let equivalentResistance: number | null = null;
  const vSource = circuit.components.find((c) => c.type === "voltage_source");
  if (vSource?.value && sourceCurrent > 1e-9) {
    equivalentResistance = vSource.value / sourceCurrent;
  } else if (resistors.length === 1 && resistors[0].value) {
    equivalentResistance = resistors[0].value;
  }

  return {
    success: true,
    nodeVoltages,
    branches,
    totalCurrent: sourceCurrent,
    equivalentResistance,
    explanations,
  };
}

function buildExplanations(
  circuit: Circuit,
  branches: BranchResult[],
  nodeVoltages: Record<string, number>,
  totalCurrent: number
): string[] {
  const steps: string[] = [];
  const vSource = circuit.components.find((c) => c.type === "voltage_source");

  if (vSource) {
    steps.push(
      `The voltage source ${vSource.id} provides ${vSource.value} V between ${vSource.nodes[0]} and ${vSource.nodes[1]}.`
    );
  }

  const resistors = circuit.components.filter(
    (c) => c.type === "resistor" || c.type === "bulb"
  );

  if (resistors.length > 0) {
    const rValues = resistors.map((r) => `${r.id} = ${r.value} Ω`).join(", ");
    steps.push(`Resistors in the circuit: ${rValues}.`);
  }

  for (const branch of branches) {
    const comp = circuit.components.find((c) => c.id === branch.componentId);
    if (!comp || comp.type === "wire") continue;

    if (comp.type === "resistor" || comp.type === "bulb") {
      steps.push(
        `${comp.id}: voltage drop ΔV = ${branch.voltageDrop.toFixed(2)} V, current I = ${Math.abs(branch.current).toFixed(3)} A, power P = ${branch.power.toFixed(2)} W.`
      );
    }
  }

  const nodeEntries = Object.entries(nodeVoltages)
    .filter(([n]) => n !== "gnd" && n !== "n0")
    .map(([n, v]) => `${n} = ${v.toFixed(2)} V`);
  if (nodeEntries.length > 0) {
    steps.push(`Node voltages (relative to ground): ${nodeEntries.join(", ")}.`);
  }

  if (totalCurrent > 0) {
    steps.push(
      `Total current from the source: I = ${totalCurrent.toFixed(3)} A (conventional current flows from + to −).`
    );
  }

  const parallelGroups = findParallelGroups(circuit);
  for (const group of parallelGroups) {
    if (group.length >= 2) {
      const invSum = group.reduce((s, id) => {
        const r = circuit.components.find((c) => c.id === id)?.value ?? 0;
        return s + 1 / r;
      }, 0);
      const rEq = 1 / invSum;
      steps.push(
        `${group.join(" and ")} are in parallel: 1/R_eq = ${group.map((id) => `1/${circuit.components.find((c) => c.id === id)?.value}`).join(" + ")} → R_eq = ${rEq.toFixed(2)} Ω.`
      );
    }
  }

  return steps;
}

function findParallelGroups(circuit: Circuit): string[][] {
  const resistors = circuit.components.filter((c) => c.type === "resistor");
  const groups: string[][] = [];
  const used = new Set<string>();

  for (const r1 of resistors) {
    if (used.has(r1.id)) continue;
    const group = [r1.id];
    for (const r2 of resistors) {
      if (r1.id === r2.id || used.has(r2.id)) continue;
      const sameNodes =
        (r1.nodes[0] === r2.nodes[0] && r1.nodes[1] === r2.nodes[1]) ||
        (r1.nodes[0] === r2.nodes[1] && r1.nodes[1] === r2.nodes[0]);
      if (sameNodes) group.push(r2.id);
    }
    if (group.length >= 2) {
      group.forEach((id) => used.add(id));
      groups.push(group);
    }
  }
  return groups;
}

