export const SYSTEM_PROMPT = `You are a circuit diagram parser for Hong Kong secondary school Physics (DC circuits only).

Convert the user's input into a JSON circuit definition. Output ONLY valid JSON, no markdown.

Schema:
{
  "name": "string",
  "components": [
    {
      "id": "unique string like V1, R1, R2",
      "type": "voltage_source" | "resistor" | "wire" | "switch" | "ammeter" | "voltmeter" | "bulb",
      "value": number (required for voltage_source in V, resistor/bulb in ohms),
      "unit": "V" | "ohm",
      "nodes": ["nodeA", "nodeB"],
      "closed": boolean (only for switch, default true)
    }
  ],
  "layout": {
    "componentId": { "x": number, "y": number }
  },
  "warnings": ["optional ambiguity notes"]
}

Rules:
- Use node names like n0, n1, n2 or gnd, top for clarity. n0 or gnd is ground (negative terminal).
- voltage_source: nodes are [positive, negative]
- All components must form a closed loop with the source
- Assign layout coordinates spread horizontally (x: 60-600, y: 100-350)
- For parallel branches, share the same two nodes
- For series, chain nodes: n0 -> n1 -> n2 -> n0
- If values are missing, use reasonable defaults and add warnings
- bulbs are resistors with type "bulb"`;

export const TEXT_USER_PREFIX = "Parse this circuit description into JSON:\n\n";
export const IMAGE_USER_PREFIX = "Parse this circuit diagram image into JSON. Identify all components, values, and connections.";

import { Router } from "express";
import multer from "multer";
import OpenAI from "openai";
import { validateCircuit } from "@circuit-visualizer/shared";
import { SYSTEM_PROMPT, TEXT_USER_PREFIX, IMAGE_USER_PREFIX } from "../llm/prompts.js";

const upload = multer({ storage: multer.memoryStorage(), limits: { fileSize: 10 * 1024 * 1024 } });
export const parseRouter = Router();

function getClient(): OpenAI | null {
  const key = process.env.OPENAI_API_KEY;
  if (!key) return null;
  return new OpenAI({ apiKey: key });
}

function extractJson(text: string): unknown {
  const trimmed = text.trim();
  const fenceMatch = trimmed.match(/```(?:json)?\s*([\s\S]*?)```/);
  const jsonStr = fenceMatch ? fenceMatch[1].trim() : trimmed;
  return JSON.parse(jsonStr);
}

async function parseWithLlm(
  client: OpenAI,
  userContent: OpenAI.Chat.Completions.ChatCompletionContentPart[]
): Promise<{ circuit?: unknown; warnings: string[]; error?: string }> {
  const model = process.env.OPENAI_MODEL || "gpt-4o-mini";

  for (let attempt = 0; attempt < 2; attempt++) {
    try {
      const response = await client.chat.completions.create({
        model,
        messages: [
          { role: "system", content: SYSTEM_PROMPT },
          { role: "user", content: userContent },
        ],
        temperature: 0.2,
        response_format: { type: "json_object" },
      });

      const content = response.choices[0]?.message?.content;
      if (!content) {
        return { warnings: [], error: "Empty response from AI" };
      }

      const parsed = extractJson(content);
      const validation = validateCircuit(parsed);
      if (validation.success) {
        return {
          circuit: validation.circuit,
          warnings: validation.circuit.warnings ?? [],
        };
      }

      if (attempt === 0) {
        userContent = [
          ...userContent,
          {
            type: "text",
            text: `Previous JSON was invalid: ${validation.errors.join("; ")}. Fix and return valid JSON only.`,
          },
        ];
        continue;
      }

      return { warnings: [], error: validation.errors.join("; ") };
    } catch (e) {
      const msg = e instanceof Error ? e.message : "Unknown error";
      if (attempt === 1) return { warnings: [], error: msg };
    }
  }

  return { warnings: [], error: "Failed to parse circuit" };
}

parseRouter.post("/parse-text", async (req, res) => {
  const client = getClient();
  if (!client) {
    res.status(503).json({
      error: "OPENAI_API_KEY not configured. Add it to backend/.env",
    });
    return;
  }

  const { text } = req.body as { text?: string };
  if (!text?.trim()) {
    res.status(400).json({ error: "text is required" });
    return;
  }

  const result = await parseWithLlm(client, [
    { type: "text", text: TEXT_USER_PREFIX + text },
  ]);

  if (result.error || !result.circuit) {
    res.status(422).json({ error: result.error ?? "Parse failed", warnings: result.warnings });
    return;
  }

  res.json({ circuit: result.circuit, warnings: result.warnings });
});

parseRouter.post("/parse-image", upload.single("image"), async (req, res) => {
  const client = getClient();
  if (!client) {
    res.status(503).json({
      error: "OPENAI_API_KEY not configured. Add it to backend/.env",
    });
    return;
  }

  if (!req.file) {
    res.status(400).json({ error: "image file is required" });
    return;
  }

  const base64 = req.file.buffer.toString("base64");
  const mime = req.file.mimetype || "image/jpeg";

  const result = await parseWithLlm(client, [
    { type: "text", text: IMAGE_USER_PREFIX },
    {
      type: "image_url",
      image_url: { url: `data:${mime};base64,${base64}` },
    },
  ]);

  if (result.error || !result.circuit) {
    res.status(422).json({ error: result.error ?? "Parse failed", warnings: result.warnings });
    return;
  }

  res.json({ circuit: result.circuit, warnings: result.warnings });
});

parseRouter.get("/health", (_req, res) => {
  res.json({
    ok: true,
    aiConfigured: !!process.env.OPENAI_API_KEY,
  });
});

import "dotenv/config";
