import { useCallback, useEffect, useMemo, useState } from "react";
import {
  type Circuit,
  validateCircuit,
  solveCircuit,
  EXAMPLE_SERIES,
} from "@circuit-visualizer/shared";
import { InputBar } from "./components/InputBar";
import { CodePanel } from "./components/CodePanel";
import { CircuitCanvas } from "./components/CircuitCanvas";
import { PhysicsPanel } from "./components/PhysicsPanel";
import "./App.css";

function circuitToJson(circuit: Circuit): string {
  return JSON.stringify(circuit, null, 2);
}

export default function App() {
  const [circuit, setCircuit] = useState<Circuit>(EXAMPLE_SERIES);
  const [code, setCode] = useState(() => circuitToJson(EXAMPLE_SERIES));
  const [codeErrors, setCodeErrors] = useState<string[]>([]);
  const [warnings, setWarnings] = useState<string[]>([]);
  const [animationPaused, setAnimationPaused] = useState(false);
  const [showOverlays, setShowOverlays] = useState(true);

  const solveResult = useMemo(() => solveCircuit(circuit), [circuit]);

  const applyCircuit = useCallback((next: Circuit, syncCode = true) => {
    setCircuit(next);
    if (syncCode) setCode(circuitToJson(next));
    setCodeErrors([]);
  }, []);

  const handleCodeChange = useCallback((value: string) => {
    setCode(value);
  }, []);

  const handleCodeApply = useCallback(() => {
    try {
      const parsed = JSON.parse(code);
      const validation = validateCircuit(parsed);
      if (!validation.success) {
        setCodeErrors(validation.errors);
        return;
      }
      setCodeErrors([]);
      setCircuit(validation.circuit);
    } catch {
      setCodeErrors(["Invalid JSON syntax"]);
    }
  }, [code]);

  const handleLayoutChange = useCallback(
    (componentId: string, x: number, y: number) => {
      setCircuit((prev) => {
        const next: Circuit = {
          ...prev,
          layout: { ...prev.layout, [componentId]: { x, y } },
        };
        setCode(circuitToJson(next));
        return next;
      });
    },
    []
  );

  const handleComponentValueChange = useCallback(
    (componentId: string, value: number) => {
      setCircuit((prev) => {
        const next: Circuit = {
          ...prev,
          components: prev.components.map((c) =>
            c.id === componentId ? { ...c, value } : c
          ),
        };
        setCode(circuitToJson(next));
        return next;
      });
    },
    []
  );

  const handleSwitchToggle = useCallback((componentId: string) => {
    setCircuit((prev) => {
      const next: Circuit = {
        ...prev,
        components: prev.components.map((c) =>
          c.id === componentId && c.type === "switch"
            ? { ...c, closed: !c.closed }
            : c
        ),
      };
      setCode(circuitToJson(next));
      return next;
    });
  }, []);

  const handleParsedCircuit = useCallback(
    (parsed: Circuit, parseWarnings: string[]) => {
      applyCircuit(parsed);
      setWarnings(parseWarnings);
    },
    [applyCircuit]
  );

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === "s") {
        e.preventDefault();
        handleCodeApply();
      }
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [handleCodeApply]);

  return (
    <div className="app">
      <header className="app-header">
        <div className="brand">
          <span className="brand-icon">⚡</span>
          <div>
            <h1>Circuit Visualizer</h1>
            <p>Physics study tool — upload, describe, or edit circuits in code</p>
          </div>
        </div>
      </header>

      <InputBar
        onCircuitParsed={handleParsedCircuit}
        onLoadExample={applyCircuit}
        warnings={warnings}
      />

      <div className="main-grid">
        <CodePanel
          code={code}
          errors={codeErrors}
          onChange={handleCodeChange}
          onApply={handleCodeApply}
          onFormat={() => {
            try {
              setCode(JSON.stringify(JSON.parse(code), null, 2));
            } catch {
              /* ignore */
            }
          }}
        />
        <div className="canvas-column">
          <div className="canvas-toolbar">
            <label className="toggle">
              <input
                type="checkbox"
                checked={showOverlays}
                onChange={(e) => setShowOverlays(e.target.checked)}
              />
              Show V / I / R labels
            </label>
            <button
              type="button"
              className="btn btn-secondary"
              onClick={() => setAnimationPaused((p) => !p)}
            >
              {animationPaused ? "Play flow" : "Pause flow"}
            </button>
          </div>
          <CircuitCanvas
            circuit={circuit}
            solveResult={solveResult}
            onLayoutChange={handleLayoutChange}
            onSwitchToggle={handleSwitchToggle}
            animationPaused={animationPaused}
            showOverlays={showOverlays}
          />
        </div>
      </div>

      <PhysicsPanel
        circuit={circuit}
        solveResult={solveResult}
        onValueChange={handleComponentValueChange}
        onSwitchToggle={handleSwitchToggle}
      />
    </div>
  );
}

import { useRef, useState } from "react";
import type { Circuit } from "@circuit-visualizer/shared";
import {
  EXAMPLE_SERIES,
  EXAMPLE_PARALLEL,
  EXAMPLE_MIXED,
} from "@circuit-visualizer/shared";

interface InputBarProps {
  onCircuitParsed: (circuit: Circuit, warnings: string[]) => void;
  onLoadExample: (circuit: Circuit) => void;
  warnings: string[];
}

export function InputBar({ onCircuitParsed, onLoadExample, warnings }: InputBarProps) {
  const [text, setText] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileRef = useRef<HTMLInputElement>(null);

  async function parseText() {
    if (!text.trim()) return;
    setLoading(true);
    setError(null);
    try {
      const res = await fetch("/api/parse-text", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Parse failed");
      onCircuitParsed(data.circuit, data.warnings ?? []);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Failed to parse");
    } finally {
      setLoading(false);
    }
  }

  async function parseImage(file: File) {
    setLoading(true);
    setError(null);
    try {
      const form = new FormData();
      form.append("image", file);
      const res = await fetch("/api/parse-image", { method: "POST", body: form });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Parse failed");
      onCircuitParsed(data.circuit, data.warnings ?? []);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Failed to parse image");
    } finally {
      setLoading(false);
    }
  }

  function onFileChange(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0];
    if (file) parseImage(file);
    e.target.value = "";
  }

  return (
    <section className="input-bar">
      <div className="input-row">
        <input
          ref={fileRef}
          type="file"
          accept="image/*"
          hidden
          onChange={onFileChange}
        />
        <button
          type="button"
          className="btn"
          onClick={() => fileRef.current?.click()}
          disabled={loading}
        >
          Upload photo / diagram
        </button>

        <div className="text-input-group">
          <input
            type="text"
            className="text-input"
            placeholder='Describe circuit, e.g. "12V battery with 4Ω and 8Ω in series"'
            value={text}
            onChange={(e) => setText(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && parseText()}
          />
          <button
            type="button"
            className="btn btn-primary"
            onClick={parseText}
            disabled={loading || !text.trim()}
          >
            {loading ? "Generating…" : "Generate circuit"}
          </button>
        </div>
      </div>

      <div className="example-row">
        <span className="example-label">Examples:</span>
        <button type="button" className="btn-chip" onClick={() => onLoadExample(EXAMPLE_SERIES)}>
          Series
        </button>
        <button type="button" className="btn-chip" onClick={() => onLoadExample(EXAMPLE_PARALLEL)}>
          Parallel
        </button>
        <button type="button" className="btn-chip" onClick={() => onLoadExample(EXAMPLE_MIXED)}>
          Mixed
        </button>
      </div>

      {error && <div className="banner banner-error">{error}</div>}
      {warnings.length > 0 && (
        <div className="banner banner-warn">
          AI notes: {warnings.join(" · ")}
        </div>
      )}
    </section>
  );
}

