import { useCallback, useMemo, useRef, useState } from "react";
import type { Circuit, Component } from "@circuit-visualizer/shared";
import type { SolveResult, SolveError } from "@circuit-visualizer/shared";

interface CircuitCanvasProps {
  circuit: Circuit;
  solveResult: SolveResult | SolveError;
  onLayoutChange: (componentId: string, x: number, y: number) => void;
  onSwitchToggle: (componentId: string) => void;
  animationPaused: boolean;
  showOverlays: boolean;
}

const COMP_WIDTH = 80;
const COMP_HEIGHT = 50;

function defaultLayout(circuit: Circuit): Record<string, { x: number; y: number }> {
  const layout = { ...circuit.layout };
  circuit.components.forEach((c, i) => {
    if (!layout[c.id]) {
      layout[c.id] = { x: 80 + i * 140, y: 200 };
    }
  });
  return layout;
}

function nodePositions(
  circuit: Circuit,
  layout: Record<string, { x: number; y: number }>
): Record<string, { x: number; y: number }> {
  const positions: Record<string, { x: number; y: number }> = {};

  for (const comp of circuit.components) {
    const pos = layout[comp.id];
    if (!pos) continue;
    const [n0, n1] = comp.nodes;
    if (!positions[n0]) positions[n0] = { x: pos.x - COMP_WIDTH / 2, y: pos.y };
    if (!positions[n1]) positions[n1] = { x: pos.x + COMP_WIDTH / 2, y: pos.y };
  }

  return positions;
}

function powerColor(power: number, maxPower: number): string {
  if (maxPower <= 0) return "transparent";
  const t = Math.min(power / maxPower, 1);
  const r = Math.round(255 * t);
  const g = Math.round(80 * (1 - t));
  const b = Math.round(80 * (1 - t));
  return `rgba(${r}, ${g}, ${b}, 0.25)`;
}

function ResistorSymbol({ id, value }: { id: string; value?: number }) {
  return (
    <g className="symbol resistor">
      <polyline
        points="-30,0 -22,-12 -14,12 -6,-12 2,12 10,-12 18,12 26,-12 30,0"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
      />
      <text y="-22" textAnchor="middle" className="symbol-label">
        {id}
      </text>
      {value !== undefined && (
        <text y="28" textAnchor="middle" className="symbol-value">
          {value} Ω
        </text>
      )}
    </g>
  );
}

function VoltageSourceSymbol({ id, value }: { id: string; value?: number }) {
  return (
    <g className="symbol voltage">
      <line x1="-20" y1="0" x2="-8" y2="0" stroke="currentColor" strokeWidth="2" />
      <line x1="8" y1="0" x2="20" y2="0" stroke="currentColor" strokeWidth="2" />
      <line x1="-8" y1="-14" x2="-8" y2="14" stroke="currentColor" strokeWidth="3" />
      <line x1="8" y1="-8" x2="8" y2="8" stroke="currentColor" strokeWidth="3" />
      <text x="-8" y="-20" textAnchor="middle" className="symbol-label">
        +
      </text>
      <text x="8" y="-20" textAnchor="middle" className="symbol-label">
        −
      </text>
      <text y="-28" textAnchor="middle" className="symbol-label">
        {id}
      </text>
      {value !== undefined && (
        <text y="28" textAnchor="middle" className="symbol-value">
          {value} V
        </text>
      )}
    </g>
  );
}

function SwitchSymbol({ id, closed }: { id: string; closed?: boolean }) {
  const isClosed = closed !== false;
  return (
    <g className="symbol switch">
      <circle cx="-20" cy="0" r="3" fill="currentColor" />
      <circle cx="20" cy="0" r="3" fill="currentColor" />
      {isClosed ? (
        <line x1="-20" y1="0" x2="20" y2="0" stroke="currentColor" strokeWidth="2" />
      ) : (
        <line x1="-20" y1="0" x2="15" y2="-12" stroke="currentColor" strokeWidth="2" />
      )}
      <text y="-22" textAnchor="middle" className="symbol-label">
        {id} {isClosed ? "(on)" : "(off)"}
      </text>
    </g>
  );
}

function MeterSymbol({ id, letter }: { id: string; letter: string }) {
  return (
    <g className="symbol meter">
      <circle cx="0" cy="0" r="18" fill="none" stroke="currentColor" strokeWidth="2" />
      <text textAnchor="middle" dominantBaseline="central" className="meter-letter">
        {letter}
      </text>
      <text y="-28" textAnchor="middle" className="symbol-label">
        {id}
      </text>
    </g>
  );
}

function BulbSymbol({ id, value }: { id: string; value?: number }) {
  return (
    <g className="symbol bulb">
      <circle cx="0" cy="0" r="16" fill="none" stroke="currentColor" strokeWidth="2" />
      <line x1="-10" y1="-10" x2="10" y2="10" stroke="currentColor" strokeWidth="2" />
      <line x1="10" y1="-10" x2="-10" y2="10" stroke="currentColor" strokeWidth="2" />
      <text y="-26" textAnchor="middle" className="symbol-label">
        {id}
      </text>
      {value !== undefined && (
        <text y="28" textAnchor="middle" className="symbol-value">
          {value} Ω
        </text>
      )}
    </g>
  );
}

function ComponentSymbol({ comp }: { comp: Component }) {
  switch (comp.type) {
    case "resistor":
      return <ResistorSymbol id={comp.id} value={comp.value} />;
    case "voltage_source":
      return <VoltageSourceSymbol id={comp.id} value={comp.value} />;
    case "switch":
      return <SwitchSymbol id={comp.id} closed={comp.closed} />;
    case "ammeter":
      return <MeterSymbol id={comp.id} letter="A" />;
    case "voltmeter":
      return <MeterSymbol id={comp.id} letter="V" />;
    case "bulb":
      return <BulbSymbol id={comp.id} value={comp.value} />;
    case "wire":
      return (
        <g>
          <line x1="-30" y1="0" x2="30" y2="0" stroke="currentColor" strokeWidth="2" />
        </g>
      );
    default:
      return null;
  }
}

export function CircuitCanvas({
  circuit,
  solveResult,
  onLayoutChange,
  onSwitchToggle,
  animationPaused,
  showOverlays,
}: CircuitCanvasProps) {
  const layout = useMemo(() => defaultLayout(circuit), [circuit]);
  const nodes = useMemo(() => nodePositions(circuit, layout), [circuit, layout]);
  const svgRef = useRef<SVGSVGElement>(null);
  const [dragging, setDragging] = useState<string | null>(null);
  const dragOffset = useRef({ x: 0, y: 0 });

  const branchMap = useMemo(() => {
    if (!solveResult.success) return new Map();
    return new Map(solveResult.branches.map((b) => [b.componentId, b]));
  }, [solveResult]);

  const maxPower = useMemo(() => {
    if (!solveResult.success) return 0;
    return Math.max(...solveResult.branches.map((b) => b.power), 0.001);
  }, [solveResult]);

  const wires = useMemo(() => {
    const segments: { x1: number; y1: number; x2: number; y2: number; key: string }[] = [];
    const nodeList = Object.entries(nodes);

    for (let i = 0; i < nodeList.length; i++) {
      for (let j = i + 1; j < nodeList.length; j++) {
        const [nA, pA] = nodeList[i];
        const [nB, pB] = nodeList[j];
        const connected = circuit.components.some(
          (c) =>
            (c.nodes[0] === nA && c.nodes[1] === nB) ||
            (c.nodes[0] === nB && c.nodes[1] === nA)
        );
        if (connected) {
          segments.push({
            x1: pA.x,
            y1: pA.y,
            x2: pB.x,
            y2: pB.y,
            key: `${nA}-${nB}`,
          });
        }
      }
    }
    return segments;
  }, [circuit, nodes]);

  const onPointerDown = useCallback(
    (id: string, e: React.PointerEvent) => {
      const pos = layout[id];
      if (!pos) return;
      (e.target as Element).setPointerCapture(e.pointerId);
      setDragging(id);
      const rect = svgRef.current?.getBoundingClientRect();
      if (!rect) return;
      dragOffset.current = {
        x: e.clientX - rect.left - pos.x,
        y: e.clientY - rect.top - pos.y,
      };
    },
    [layout]
  );

  const onPointerMove = useCallback(
    (e: React.PointerEvent) => {
      if (!dragging) return;
      const rect = svgRef.current?.getBoundingClientRect();
      if (!rect) return;
      const x = e.clientX - rect.left - dragOffset.current.x;
      const y = e.clientY - rect.top - dragOffset.current.y;
      onLayoutChange(dragging, x, y);
    },
    [dragging, onLayoutChange]
  );

  const onPointerUp = useCallback(() => setDragging(null), []);

  return (
    <section className="circuit-canvas">
      <svg
        ref={svgRef}
        viewBox="0 0 700 420"
        className="circuit-svg"
        onPointerMove={onPointerMove}
        onPointerUp={onPointerUp}
        onPointerLeave={onPointerUp}
      >
        <defs>
          <marker
            id="arrowhead"
            markerWidth="8"
            markerHeight="8"
            refX="6"
            refY="3"
            orient="auto"
          >
            <polygon points="0 0, 8 3, 0 6" fill="#f59e0b" />
          </marker>
        </defs>

        {/* Wires between nodes */}
        {wires.map((w) => (
          <line
            key={w.key}
            x1={w.x1}
            y1={w.y1}
            x2={w.x2}
            y2={w.y2}
            className="wire-line"
            stroke="#64748b"
            strokeWidth="2"
          />
        ))}

        {/* Current flow animation along components */}
        {solveResult.success &&
          !animationPaused &&
          circuit.components.map((comp) => {
            const branch = branchMap.get(comp.id);
            const pos = layout[comp.id];
            if (!branch || !pos || Math.abs(branch.current) < 1e-6) return null;
            const speed = Math.min(Math.abs(branch.current) * 3, 4);
            const reverse = branch.current < 0;
            return (
              <g key={`flow-${comp.id}`}>
                <line
                  x1={pos.x - 28}
                  y1={pos.y}
                  x2={pos.x + 28}
                  y2={pos.y}
                  className="current-flow-line"
                  stroke="#f59e0b"
                  strokeWidth="3"
                  strokeDasharray="8 12"
                  markerEnd="url(#arrowhead)"
                  style={{
                    animationDuration: `${1 / speed}s`,
                    animationDirection: reverse ? "reverse" : "normal",
                  }}
                />
              </g>
            );
          })}

        {/* Components */}
        {circuit.components.map((comp) => {
          const pos = layout[comp.id];
          if (!pos) return null;
          const branch = branchMap.get(comp.id);
          const heat = branch ? powerColor(branch.power, maxPower) : "transparent";

          return (
            <g
              key={comp.id}
              transform={`translate(${pos.x}, ${pos.y})`}
              className={`component ${dragging === comp.id ? "dragging" : ""}`}
              onPointerDown={(e) => onPointerDown(comp.id, e)}
              onDoubleClick={() => comp.type === "switch" && onSwitchToggle(comp.id)}
              style={{ cursor: "grab" }}
            >
              <rect
                x={-COMP_WIDTH / 2}
                y={-COMP_HEIGHT / 2}
                width={COMP_WIDTH}
                height={COMP_HEIGHT}
                fill={heat}
                rx="6"
              />
              <ComponentSymbol comp={comp} />
              {showOverlays && branch && comp.type !== "wire" && (
                <g className="overlay-labels">
                  <text y="42" textAnchor="middle" className="overlay-text">
                    I={Math.abs(branch.current).toFixed(2)}A ΔV={Math.abs(branch.voltageDrop).toFixed(1)}V
                  </text>
                </g>
              )}
            </g>
          );
        })}

        {/* Node voltage labels */}
        {showOverlays &&
          solveResult.success &&
          Object.entries(nodes).map(([nodeId, pos]) => {
            const v = solveResult.nodeVoltages[nodeId];
            if (v === undefined) return null;
            return (
              <g key={`node-${nodeId}`} transform={`translate(${pos.x}, ${pos.y - 18})`}>
                <text textAnchor="middle" className="node-label">
                  {nodeId}: {v.toFixed(1)}V
                </text>
              </g>
            );
          })}
      </svg>

      {!solveResult.success && (
        <div className="canvas-error">{solveResult.error}</div>
      )}
    </section>
  );
}

import type { Circuit } from "@circuit-visualizer/shared";
import type { SolveResult, SolveError } from "@circuit-visualizer/shared";

interface PhysicsPanelProps {
  circuit: Circuit;
  solveResult: SolveResult | SolveError;
  onValueChange: (componentId: string, value: number) => void;
  onSwitchToggle: (componentId: string) => void;
}

export function PhysicsPanel({
  circuit,
  solveResult,
  onValueChange,
  onSwitchToggle,
}: PhysicsPanelProps) {
  const adjustable = circuit.components.filter(
    (c) =>
      c.type === "voltage_source" ||
      c.type === "resistor" ||
      c.type === "bulb" ||
      c.type === "switch"
  );

  return (
    <section className="physics-panel">
      <h2>Physics results</h2>

      {!solveResult.success ? (
        <p className="physics-error">{solveResult.error}</p>
      ) : (
        <div className="physics-grid">
          <div className="stat-card">
            <span className="stat-label">Total current</span>
            <span className="stat-value">{solveResult.totalCurrent.toFixed(3)} A</span>
          </div>
          <div className="stat-card">
            <span className="stat-label">Equivalent resistance</span>
            <span className="stat-value">
              {solveResult.equivalentResistance !== null
                ? `${solveResult.equivalentResistance.toFixed(2)} Ω`
                : "—"}
            </span>
          </div>
          <div className="stat-card wide">
            <span className="stat-label">Power dissipation</span>
            <span className="stat-value">
              {solveResult.branches
                .filter((b) => b.power > 0.001)
                .map((b) => `${b.componentId}: ${b.power.toFixed(2)} W`)
                .join(" · ") || "—"}
            </span>
          </div>
        </div>
      )}

      {adjustable.length > 0 && (
        <div className="controls-section">
          <h3>Interactive controls</h3>
          <div className="sliders">
            {adjustable.map((comp) => {
              if (comp.type === "switch") {
                return (
                  <label key={comp.id} className="slider-row">
                    <span>{comp.id} (switch)</span>
                    <button
                      type="button"
                      className="btn btn-secondary"
                      onClick={() => onSwitchToggle(comp.id)}
                    >
                      {comp.closed !== false ? "Open" : "Close"}
                    </button>
                  </label>
                );
              }
              const min = comp.type === "voltage_source" ? 1 : 0.5;
              const max = comp.type === "voltage_source" ? 24 : 50;
              const step = comp.type === "voltage_source" ? 0.5 : 0.5;
              const unit = comp.type === "voltage_source" ? "V" : "Ω";
              return (
                <label key={comp.id} className="slider-row">
                  <span>
                    {comp.id}: {comp.value ?? 0} {unit}
                  </span>
                  <input
                    type="range"
                    min={min}
                    max={max}
                    step={step}
                    value={comp.value ?? min}
                    onChange={(e) => onValueChange(comp.id, parseFloat(e.target.value))}
                  />
                </label>
              );
            })}
          </div>
        </div>
      )}

      {solveResult.success && (
        <div className="explanations-section">
          <h3>Step-by-step study notes</h3>
          <ol className="explanation-list">
            {solveResult.explanations.map((step, i) => (
              <li key={i}>{step}</li>
            ))}
          </ol>
        </div>
      )}

      <div className="legend">
        <h3>Diagram legend</h3>
        <ul>
          <li>
            <span className="legend-dot flow" /> Animated arrows = conventional current (+ → −)
          </li>
          <li>
            <span className="legend-dot heat" /> Red tint = power dissipation (heat)
          </li>
          <li>Double-click a switch to toggle open/closed</li>
          <li>Drag components to adjust layout (updates JSON)</li>
        </ul>
      </div>
    </section>
  );
}

:root {
  --bg: #0f1419;
  --surface: #1a2332;
  --surface-2: #243044;
  --border: #2d3f56;
  --text: #e8eef4;
  --text-muted: #94a3b8;
  --accent: #3b82f6;
  --accent-hover: #2563eb;
  --success: #22c55e;
  --warn: #f59e0b;
  --error: #ef4444;
  --font: "DM Sans", system-ui, sans-serif;
  --mono: "JetBrains Mono", monospace;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family: var(--font);
  background: var(--bg);
  color: var(--text);
  line-height: 1.5;
}

#root {
  min-height: 100vh;
}

button {
  font-family: var(--font);
}

input[type="text"],
input[type="range"] {
  font-family: var(--font);
}

@keyframes flowDash {
  to {
    stroke-dashoffset: -40;
  }
}

.current-flow-line {
  animation: flowDash 1s linear infinite;
  pointer-events: none;
}

.app {
  max-width: 1400px;
  margin: 0 auto;
  padding: 1rem 1.25rem 2rem;
}

.app-header {
  margin-bottom: 1rem;
}

.brand {
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.brand-icon {
  font-size: 2rem;
}

.brand h1 {
  margin: 0;
  font-size: 1.5rem;
  font-weight: 700;
}

.brand p {
  margin: 0.15rem 0 0;
  color: var(--text-muted);
  font-size: 0.9rem;
}

.input-bar {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 1rem;
  margin-bottom: 1rem;
}

.input-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  align-items: center;
}

.text-input-group {
  display: flex;
  flex: 1;
  min-width: 280px;
  gap: 0.5rem;
}

.text-input {
  flex: 1;
  padding: 0.55rem 0.75rem;
  border-radius: 8px;
  border: 1px solid var(--border);
  background: var(--surface-2);
  color: var(--text);
  font-size: 0.95rem;
}

.text-input:focus {
  outline: 2px solid var(--accent);
  border-color: transparent;
}

.example-row {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  margin-top: 0.75rem;
  flex-wrap: wrap;
}

.example-label {
  color: var(--text-muted);
  font-size: 0.85rem;
}

.btn {
  padding: 0.5rem 1rem;
  border-radius: 8px;
  border: 1px solid var(--border);
  background: var(--surface-2);
  color: var(--text);
  cursor: pointer;
  font-size: 0.9rem;
  font-weight: 500;
  transition: background 0.15s;
}

.btn:hover:not(:disabled) {
  background: var(--border);
}

.btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.btn-primary {
  background: var(--accent);
  border-color: var(--accent);
  color: white;
}

.btn-primary:hover:not(:disabled) {
  background: var(--accent-hover);
}

.btn-secondary {
  background: transparent;
}

.btn-chip {
  padding: 0.25rem 0.65rem;
  border-radius: 999px;
  border: 1px solid var(--border);
  background: transparent;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 0.8rem;
}

.btn-chip:hover {
  border-color: var(--accent);
  color: var(--text);
}

.banner {
  margin-top: 0.75rem;
  padding: 0.5rem 0.75rem;
  border-radius: 8px;
  font-size: 0.9rem;
}

.banner-error {
  background: rgba(239, 68, 68, 0.15);
  border: 1px solid var(--error);
  color: #fca5a5;
}

.banner-warn {
  background: rgba(245, 158, 11, 0.12);
  border: 1px solid var(--warn);
  color: #fcd34d;
}

.main-grid {
  display: grid;
  grid-template-columns: 1fr 1.2fr;
  gap: 1rem;
  min-height: 420px;
}

@media (max-width: 900px) {
  .main-grid {
    grid-template-columns: 1fr;
  }
}

.code-panel,
.canvas-column {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 12px;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.panel-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.75rem 1rem;
  border-bottom: 1px solid var(--border);
}

.panel-header h2 {
  margin: 0;
  font-size: 1rem;
}

.panel-actions {
  display: flex;
  gap: 0.5rem;
}

.panel-hint {
  margin: 0;
  padding: 0.35rem 1rem;
  font-size: 0.8rem;
  color: var(--text-muted);
  border-bottom: 1px solid var(--border);
}

.error-list {
  margin: 0;
  padding: 0.5rem 1rem;
  list-style: none;
  background: rgba(239, 68, 68, 0.1);
  color: #fca5a5;
  font-size: 0.85rem;
}

.error-list li + li {
  margin-top: 0.25rem;
}

.editor-wrap {
  flex: 1;
  min-height: 360px;
}

.canvas-toolbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.5rem 1rem;
  border-bottom: 1px solid var(--border);
}

.toggle {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  font-size: 0.85rem;
  color: var(--text-muted);
  cursor: pointer;
}

.circuit-canvas {
  flex: 1;
  position: relative;
  min-height: 380px;
}

.circuit-svg {
  width: 100%;
  height: 100%;
  min-height: 380px;
  background: #121a24;
}

.circuit-svg .symbol {
  color: var(--text);
}

.symbol-label {
  font-size: 11px;
  fill: var(--text-muted);
  font-family: var(--mono);
}

.symbol-value {
  font-size: 10px;
  fill: var(--warn);
  font-family: var(--mono);
}

.meter-letter {
  font-size: 16px;
  font-weight: 700;
  fill: var(--text);
  font-family: var(--font);
}

.overlay-text {
  font-size: 9px;
  fill: #fbbf24;
  font-family: var(--mono);
}

.node-label {
  font-size: 9px;
  fill: #60a5fa;
  font-family: var(--mono);
}

.component.dragging {
  opacity: 0.85;
}

.canvas-error {
  position: absolute;
  bottom: 1rem;
  left: 1rem;
  right: 1rem;
  padding: 0.5rem 0.75rem;
  background: rgba(239, 68, 68, 0.2);
  border: 1px solid var(--error);
  border-radius: 8px;
  font-size: 0.9rem;
  color: #fca5a5;
}

.physics-panel {
  margin-top: 1rem;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 1rem 1.25rem;
}

.physics-panel h2 {
  margin: 0 0 0.75rem;
  font-size: 1.1rem;
}

.physics-panel h3 {
  margin: 1rem 0 0.5rem;
  font-size: 0.95rem;
  color: var(--text-muted);
}

.physics-error {
  color: #fca5a5;
}

.physics-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 0.75rem;
}

.stat-card {
  background: var(--surface-2);
  border-radius: 8px;
  padding: 0.75rem 1rem;
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.stat-card.wide {
  grid-column: 1 / -1;
}

.stat-label {
  font-size: 0.8rem;
  color: var(--text-muted);
}

.stat-value {
  font-size: 1.1rem;
  font-weight: 600;
  font-family: var(--mono);
  color: var(--success);
}

.sliders {
  display: flex;
  flex-direction: column;
  gap: 0.65rem;
}

.slider-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  font-size: 0.9rem;
}

.slider-row input[type="range"] {
  flex: 1;
  max-width: 280px;
  accent-color: var(--accent);
}

.explanation-list {
  margin: 0;
  padding-left: 1.25rem;
  font-size: 0.9rem;
  color: var(--text-muted);
}

.explanation-list li + li {
  margin-top: 0.35rem;
}

.legend ul {
  margin: 0;
  padding-left: 1.25rem;
  font-size: 0.85rem;
  color: var(--text-muted);
}

.legend-dot {
  display: inline-block;
  width: 10px;
  height: 10px;
  border-radius: 50%;
  margin-right: 0.35rem;
  vertical-align: middle;
}

.legend-dot.flow {
  background: var(--warn);
}

.legend-dot.heat {
  background: rgba(239, 68, 68, 0.6);
}

