async function parseWithLlm(
  client: OpenAI,
  userContent: OpenAI.Chat.Completions.ChatCompletionContentPart[]
): Promise<{ circuit?: unknown; warnings: string[]; error?: string }> {
  const model = process.env.OPENAI_MODEL || "gpt-4o-mini";
  let lastValidationError = "";

  for (let attempt = 0; attempt < 2; attempt++) {
    try {
      const messages: OpenAI.Chat.Completions.ChatCompletionMessageParam[] = [
        { role: "system", content: SYSTEM_PROMPT },
        { role: "user", content: userContent },
      ];

      if (attempt > 0 && lastValidationError) {
        messages.push({
          role: "user",
          content: `Previous JSON was invalid: ${lastValidationError}. Fix and return valid JSON only.`,
        });
      }

      const response = await client.chat.completions.create({
        model,
        messages,
        temperature: 0.2,
        response_format: { type: "json_object" },
      });

      const content = response.choices[0]?.message?.content;
      if (!content) {
        return { warnings: [], error: "Empty response from AI" };
      }

      const parsed = extractJson(content);
      const validation = validateCircuit(parsed);
      if (validation.success) {
        return {
          circuit: validation.circuit,
          warnings: validation.circuit.warnings ?? [],
        };
      }

      lastValidationError = validation.errors.join("; ");
      if (attempt === 1) {
        return { warnings: [], error: lastValidationError };
      }
    } catch (e) {
      const msg = e instanceof Error ? e.message : "Unknown error";
      if (attempt === 1) return { warnings: [], error: msg };
    }
  }

  return { warnings: [], error: "Failed to parse circuit" };
}

